//! Error handling example for TemplateFlow Rust library
//!
//! This example demonstrates how to properly handle errors and edge cases:
//! - Template not found errors
//! - No files matching query
//! - Network/download errors
//! - Cache issues

use std::collections::HashMap;
use templateflow::{get, ls, templates, get_metadata, TemplateFlowError};

fn main() {
    println!("=== TemplateFlow Error Handling Example ===\n");

    // 1. Handle template not found error
    println!("1. Handling template not found:");
    match get_metadata("NonExistentTemplate") {
        Ok(_) => println!("   Unexpected: template found!"),
        Err(TemplateFlowError::TemplateNotFound(name)) => {
            println!("   ✓ Correctly caught TemplateNotFound error for '{}'", name);
        }
        Err(e) => println!("   Different error: {}", e),
    }
    println!();

    // 2. Handle no files matching query
    println!("2. Handling no files matching query:");
    let mut impossible_query = HashMap::new();
    impossible_query.insert("resolution".to_string(), "999".to_string());
    impossible_query.insert("suffix".to_string(), "NonExistentSuffix".to_string());

    match ls("MNI152NLin2009cAsym", Some(&impossible_query)) {
        Ok(files) => {
            if files.is_empty() {
                println!("   ✓ Query returned empty list (no matches)");
            } else {
                println!("   Unexpected: found {} files", files.len());
            }
        }
        Err(e) => println!("   Error: {}", e),
    }
    println!();

    // 3. Handle download errors gracefully
    println!("3. Handling download errors:");
    match get("MNI152NLin2009cAsym", Some(&impossible_query)) {
        Ok(files) => {
            if files.is_empty() {
                println!("   ✓ No files to download (empty result)");
            }
        }
        Err(TemplateFlowError::NoFilesMatched) => {
            println!("   ✓ Correctly caught NoFilesMatched error");
        }
        Err(e) => println!("   Error: {}", e),
    }
    println!();

    // 4. Check template existence before operations
    println!("4. Checking template existence:");
    let test_template = "MNI152NLin6Asym";

    let all_templates = templates(None).unwrap_or_default();
    if all_templates.contains(&test_template.to_string()) {
        println!("   ✓ Template '{}' exists", test_template);

        // Safe to proceed with operations
        match ls(test_template, None) {
            Ok(files) => println!("   Found {} files", files.len()),
            Err(e) => println!("   Error listing files: {}", e),
        }
    } else {
        println!("   ✗ Template '{}' does not exist", test_template);
    }
    println!();

    // 5. Robust query with fallbacks
    println!("5. Robust querying with fallbacks:");
    let template = "MNI152NLin2009cAsym";

    // Try high resolution first, fall back to lower resolutions
    let resolutions = ["1", "2", "09"];
    let mut found = false;

    for res in &resolutions {
        let mut query = HashMap::new();
        query.insert("resolution".to_string(), res.to_string());
        query.insert("suffix".to_string(), "T1w".to_string());

        match ls(template, Some(&query)) {
            Ok(files) if !files.is_empty() => {
                println!("   ✓ Found T1w at resolution {}: {} files", res, files.len());
                found = true;
                break;
            }
            Ok(_) => continue,
            Err(e) => {
                println!("   Error at resolution {}: {}", res, e);
                break;
            }
        }
    }

    if !found {
        println!("   ✗ No T1w files found at any resolution");
    }
    println!();

    // 6. Error recovery pattern
    println!("6. Error recovery pattern:");
    let result: Result<(), Box<dyn std::error::Error>> = (|| {
        // Try to get metadata
        let metadata = get_metadata("MNI152NLin2009cAsym")?;
        println!("   Got metadata for: {}", metadata.name);

        // Try to list files
        let files = ls("MNI152NLin2009cAsym", None)?;
        println!("   Listed {} files", files.len());

        // Try to download (with query that might fail)
        let mut query = HashMap::new();
        query.insert("suffix".to_string(), "T1w".to_string());
        let downloaded = get("MNI152NLin2009cAsym", Some(&query))?;
        println!("   Downloaded {} files", downloaded.len());

        Ok(())
    })();

    match result {
        Ok(()) => println!("   ✓ All operations completed successfully"),
        Err(e) => println!("   ✗ Operation failed: {}", e),
    }

    println!("\n=== Error handling example completed! ===");
}

