//! Configuration example for TemplateFlow Rust library
//!
//! This example demonstrates how to work with configuration:
//! - Environment variables
//! - Cache management
//! - Custom configurations
//! - Skeleton updates

use std::env;
use std::path::PathBuf;
use templateflow::{Config, templates, update_skeleton};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("=== TemplateFlow Configuration Example ===\n");

    // 1. Display current configuration
    println!("1. Current Configuration:");
    let config = Config::from_env();
    println!("   Cache home: {}", config.home.display());
    println!("   S3 root: {}", config.s3_root);
    println!("   Auto-update: {}", config.autoupdate);
    println!("   Timeout: {:?}", config.timeout);
    println!();

    // 2. Check environment variables
    println!("2. Environment Variables:");
    let env_vars = [
        "TEMPLATEFLOW_HOME",
        "TEMPLATEFLOW_S3_ROOT",
        "TEMPLATEFLOW_AUTOUPDATE",
        "TEMPLATEFLOW_TIMEOUT",
    ];

    for var in &env_vars {
        match env::var(var) {
            Ok(value) => println!("   {} = '{}'", var, value),
            Err(_) => println!("   {} = <not set>", var),
        }
    }
    println!();

    // 3. Cache locations
    println!("3. Cache Locations:");
    let cache_dir = &config.home;
    println!("   Main cache: {}", cache_dir.display());

    let skeleton_path = cache_dir.join("templateflow-skel.zip");
    println!("   Skeleton file: {}", skeleton_path.display());

    if skeleton_path.exists() {
        let metadata = std::fs::metadata(&skeleton_path)?;
        println!("   Skeleton size: {} bytes", metadata.len());

        if let Ok(modified) = metadata.modified() {
            if let Ok(elapsed) = modified.elapsed() {
                let days = elapsed.as_secs() / 86400;
                println!("   Last updated: {} days ago", days);
            }
        }
    } else {
        println!("   Skeleton not downloaded yet");
    }
    println!();

    // 4. Check cache contents
    println!("4. Cache Contents:");
    if cache_dir.exists() {
        let mut template_count = 0;
        let mut file_count = 0;
        let mut total_size = 0u64;

        // Walk through cache directory
        for entry in std::fs::read_dir(cache_dir)? {
            let entry = entry?;
            let path = entry.path();

            if path.is_dir() && path.file_name()
                .and_then(|n| n.to_str())
                .map(|n| n.starts_with("tpl-"))
                .unwrap_or(false) 
            {
                template_count += 1;

                // Count files in template directory
                for file in walkdir::WalkDir::new(&path)
                    .into_iter()
                    .filter_map(|e| e.ok())
                    .filter(|e| e.file_type().is_file())
                {
                    file_count += 1;
                    if let Ok(metadata) = file.metadata() {
                        total_size += metadata.len();
                    }
                }
            }
        }

        println!("   Cached templates: {}", template_count);
        println!("   Cached files: {}", file_count);
        println!("   Total size: {:.2} MB", total_size as f64 / 1_048_576.0);
    } else {
        println!("   Cache directory does not exist yet");
    }
    println!();

    // 5. Update skeleton (if needed)
    println!("5. Skeleton Management:");
    if !skeleton_path.exists() || config.autoupdate {
        println!("   Checking for skeleton updates...");
        match update_skeleton() {
            Ok(updated) => {
                if updated {
                    println!("   ✓ Skeleton updated successfully");
                } else {
                    println!("   ✓ Skeleton is already up to date");
                }
            }
            Err(e) => println!("   ✗ Error updating skeleton: {}", e),
        }
    } else {
        println!("   Auto-update is disabled");
    }
    println!();

    // 6. List available templates
    println!("6. Available Templates:");
    match templates(None) {
        Ok(template_list) => {
            println!("   Total templates: {}", template_list.len());
            println!("   Sample templates:");
            for (i, template) in template_list.iter().take(5).enumerate() {
                println!("     {}. {}", i + 1, template);
            }
            if template_list.len() > 5 {
                println!("     ... and {} more", template_list.len() - 5);
            }
        }
        Err(e) => println!("   Error listing templates: {}", e),
    }
    println!();

    // 7. Custom configuration example
    println!("7. Custom Configuration (example):");
    println!("   To use a custom cache location:");
    println!("     export TEMPLATEFLOW_HOME=/path/to/custom/cache");
    println!();
    println!("   To use a different S3 endpoint:");
    println!("     export TEMPLATEFLOW_S3_ROOT=https://custom-s3-endpoint.com");
    println!();
    println!("   To disable auto-updates:");
    println!("     export TEMPLATEFLOW_AUTOUPDATE=false");
    println!();
    println!("   To set a custom timeout (in seconds):");
    println!("     export TEMPLATEFLOW_TIMEOUT=120");

    println!("\n=== Configuration example completed! ===");

    Ok(())
}

