use criterion::{black_box, criterion_group, criterion_main, Criterion, BenchmarkId};
use std::collections::HashMap;
use std::time::Duration;
use templateflow::{api, bids::{TemplateLayout, load_skeleton_from_file}};
use std::path::Path;

/// Benchmark core operations without external dependencies
fn benchmark_core_operations(c: &mut Criterion) {
    let skeleton_path = Path::new("templateflow-skel.zip");

    // Ensure skeleton exists for benchmarks
    if !skeleton_path.exists() {
        eprintln!("Warning: templateflow-skel.zip not found. Downloading...");
        if let Err(e) = api::update_skeleton() {
            eprintln!("Failed to download skeleton: {}", e);
            return;
        }
    }

    let mut group = c.benchmark_group("core_operations");

    // Benchmark: Parse skeleton file
    group.bench_function("parse_skeleton", |b| {
        b.iter(|| {
            let layout = load_skeleton_from_file(black_box(skeleton_path))
                .expect("Failed to load skeleton");
            black_box(layout.templates.len());
        });
    });

    // Load layout once for query benchmarks
    let layout = load_skeleton_from_file(skeleton_path)
        .expect("Failed to load skeleton for benchmarks");

    // Benchmark: Simple query
    group.bench_function("simple_query", |b| {
        let mut query = HashMap::new();
        query.insert("suffix".to_string(), "T1w".to_string());

        b.iter(|| {
            let results = layout.query(black_box(&query));
            black_box(results.len());
        });
    });

    // Benchmark: Complex query
    group.bench_function("complex_query", |b| {
        let mut query = HashMap::new();
        query.insert("tpl".to_string(), "MNI152NLin2009cAsym".to_string());
        query.insert("res".to_string(), "01".to_string());
        query.insert("suffix".to_string(), "T1w".to_string());
        query.insert("desc".to_string(), "brain".to_string());

        b.iter(|| {
            let results = layout.query(black_box(&query));
            black_box(results.len());
        });
    });

    // Benchmark: Get all templates
    group.bench_function("get_all_templates", |b| {
        b.iter(|| {
            let templates = layout.get_templates();
            black_box(templates.len());
        });
    });

    // Benchmark: Get template metadata
    group.bench_function("get_template_metadata", |b| {
        b.iter(|| {
            let metadata = layout.get_metadata(black_box("MNI152NLin2009cAsym"));
            black_box(metadata.is_some());
        });
    });

    group.finish();
}

/// Benchmark query performance with different dataset sizes
fn benchmark_query_scaling(c: &mut Criterion) {
    let skeleton_path = Path::new("templateflow-skel.zip");

    if !skeleton_path.exists() {
        eprintln!("Skeleton file not found, skipping scaling benchmarks");
        return;
    }

    let layout = load_skeleton_from_file(skeleton_path)
        .expect("Failed to load skeleton");

    let mut group = c.benchmark_group("query_scaling");
    group.measurement_time(Duration::from_secs(10));

    // Different query complexities
    let queries = vec![
        ("single_common", vec![("suffix", "T1w")]),
        ("single_rare", vec![("atlas", "Yeo2011")]),
        ("double_filter", vec![("suffix", "T1w"), ("res", "01")]),
        ("triple_filter", vec![("suffix", "T1w"), ("res", "01"), ("desc", "brain")]),
        ("specific_template", vec![("tpl", "MNI152NLin2009cAsym"), ("suffix", "T1w")]),
    ];

    for (name, entities) in queries {
        let mut query = HashMap::new();
        for (key, value) in &entities {
            query.insert(key.to_string(), value.to_string());
        }

        group.bench_with_input(
            BenchmarkId::from_parameter(name),
            &query,
            |b, q| {
                b.iter(|| {
                    let results = layout.query(black_box(q));
                    black_box(results.len());
                });
            },
        );
    }

    group.finish();
}

/// Benchmark API-level operations
fn benchmark_api_operations(c: &mut Criterion) {
    let skeleton_path = Path::new("templateflow-skel.zip");

    if !skeleton_path.exists() {
        eprintln!("Skeleton file not found, skipping API benchmarks");
        return;
    }

    let mut group = c.benchmark_group("api_operations");

    // Benchmark: List templates via API
    group.bench_function("api_templates", |b| {
        b.iter(|| {
            let templates = api::templates(&HashMap::new()).unwrap();
            black_box(templates.len());
        });
    });

    // Benchmark: List files via API
    group.bench_function("api_ls", |b| {
        let mut query = HashMap::new();
        query.insert("res".to_string(), "01".to_string());

        b.iter(|| {
            let files = api::ls("MNI152NLin2009cAsym", &query).unwrap();
            black_box(files.len());
        });
    });

    // Benchmark: Get metadata via API
    group.bench_function("api_get_metadata", |b| {
        b.iter(|| {
            let metadata = api::get_metadata("MNI152NLin2009cAsym").unwrap();
            black_box(&metadata.name);
        });
    });

    group.finish();
}

criterion_group!(
    benches,
    benchmark_core_operations,
    benchmark_query_scaling,
    benchmark_api_operations
);
criterion_main!(benches);

