//! Integration tests for the API module

use templateflow::{get_metadata, templates, ls, get};
use std::collections::HashMap;

#[test]
#[ignore] // Ignore by default since it requires downloading the skeleton
fn test_templates() {
    // Test listing all templates
    let all_templates = templates(None).unwrap();
    assert!(!all_templates.is_empty());
    assert!(all_templates.contains(&"MNI152NLin2009cAsym".to_string()));

    // Test filtering templates
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());
    let filtered = templates(Some(&query)).unwrap();
    assert!(!filtered.is_empty());
}

#[test]
#[ignore] // Ignore by default since it requires downloading the skeleton
fn test_ls() {
    // Test listing all files for a template
    let files = ls("MNI152NLin2009cAsym", None).unwrap();
    assert!(!files.is_empty());

    // Test listing files with a specific query
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    let filtered = ls("MNI152NLin2009cAsym", Some(&query)).unwrap();
    assert!(!filtered.is_empty());
    assert!(filtered.len() < files.len());
}

#[test]
#[ignore] // Ignore by default since it requires downloading actual files
fn test_get() {
    // First get available files to see what's available
    let available_files = ls("MNI152NLin2009cAsym", None).unwrap();
    println!("Available files: {:?}", available_files);

    // Test downloading files with a more flexible query
    let mut query = HashMap::new();
    query.insert("res".to_string(), "01".to_string());
    query.insert("suffix".to_string(), "T1w".to_string());

    match get("MNI152NLin2009cAsym", Some(&query)) {
        Ok(files) => {
            assert!(!files.is_empty(), "Should find at least one file");
            // Verify the file was downloaded
            assert!(files[0].exists());
        }
        Err(e) => {
            // If no files matched, try a simpler query
            let files = get("MNI152NLin2009cAsym", None).unwrap();
            assert!(!files.is_empty(), "Should have at least one file for the template");
        }
    }
}

#[test]
#[ignore] // Ignore by default since it requires downloading the skeleton
fn test_get_metadata() {
    let metadata = get_metadata("MNI152NLin2009cAsym").unwrap();
    assert_eq!(metadata.name, "ICBM 152 Nonlinear Asymmetrical");
    assert!(metadata.authors.len() > 0);
}

