/// Benchmark querying all templates for T1w files
fn benchmark_query_all_templates_t1w(c: &mut Criterion) {
    let mut group = c.benchmark_group("query_all_t1w");
    group.measurement_time(Duration::from_secs(10));
    group.sample_size(10);

    group.bench_function("rust_query_all_templates_t1w", |b| {
        b.iter(|| {
            let templates = api::templates(None).unwrap();
            let mut all_files = Vec::new();
            let mut query = HashMap::new();
            query.insert("suffix".to_string(), "T1w".to_string());

            for template in &templates {
                if let Ok(files) = api::ls(template, Some(&query)) {
                    all_files.extend(files);
                }
            }
            black_box(all_files.len());
        });
    });

    group.finish();
}

/// Run all comparison benchmarks
fn run_comparison_suite(c: &mut Criterion) {
    println!("\nTemplateFlow Rust Benchmark");
    println!("==========================");
    println!("Rust version: {}", env!("CARGO_PKG_VERSION"));
    println!("Configuration:");
    let config = Config::new().unwrap();
    println!("  Cache: {:?}", config.home);
    println!("  S3 Root: {}", config.s3_root);
    println!();

    // Run individual benchmarks
    benchmark_list_templates(c);
    benchmark_list_files_single_entity(c);
    benchmark_list_files_multiple_entities(c);
    benchmark_get_metadata(c);
    benchmark_get_citations(c);
    benchmark_query_all_templates_t1w(c);
}

criterion_group!(
    benches,
    run_comparison_suite
);
criterion_main!(benches);

