use std::collections::HashMap;
use std::time::Instant;
use templateflow::{api, Config};
use serde_json::json;

/// Time an operation over multiple iterations
fn time_operation<F>(name: &str, description: &str, iterations: usize, mut operation: F) -> serde_json::Value
where
    F: FnMut() -> Result<(), Box<dyn std::error::Error>>,
{
    let mut times = Vec::new();

    for _ in 0..iterations {
        let start = Instant::now();
        match operation() {
            Ok(_) => {
                let elapsed = start.elapsed();
                times.push(elapsed.as_secs_f64());
            }
            Err(e) => {
                return json!({
                    "name": name,
                    "description": description,
                    "error": format!("Operation failed: {}", e)
                });
            }
        }
    }

    // Calculate statistics
    let mean = times.iter().sum::<f64>() / times.len() as f64;
    let min = times.iter().fold(f64::INFINITY, |a, &b| a.min(b));
    let max = times.iter().fold(f64::NEG_INFINITY, |a, &b| a.max(b));

    // Calculate standard deviation
    let variance = times.iter()
        .map(|&x| (x - mean).powi(2))
        .sum::<f64>() / times.len() as f64;
    let stdev = variance.sqrt();

    json!({
        "name": name,
        "description": description,
        "timing": {
            "mean": mean,
            "min": min,
            "max": max,
            "stdev": stdev,
            "iterations": iterations
        }
    })
}

fn main() {
    println!("TemplateFlow Rust Benchmark (JSON Output)");
    println!("========================================");
    println!("Version: {}", env!("CARGO_PKG_VERSION"));

    let config = Config::new().unwrap();
    println!("Cache: {:?}", config.home);
    println!("S3 Root: {}\n", config.s3_root);

    let mut results = HashMap::new();

    // Benchmark: List all templates
    let result = time_operation(
        "list_templates",
        "List all available templates",
        20,
        || {
            let templates = api::templates(None)?;
            Ok(())
        }
    );
    results.insert("list_templates", result);

    // Benchmark: List files with single entity
    let result = time_operation(
        "list_files_single_entity",
        "List files with single entity (resolution=01)",
        20,
        || {
            let mut query = HashMap::new();
            query.insert("res".to_string(), "01".to_string());
            let files = api::ls("MNI152Lin", Some(&query))?;
            Ok(())
        }
    );
    results.insert("list_files_single_entity", result);

    // Benchmark: List files with multiple entities
    let result = time_operation(
        "list_files_multiple_entities",
        "List files with multiple entities (resolution=01, suffix=T1w)",
        20,
        || {
            let mut query = HashMap::new();
            query.insert("res".to_string(), "01".to_string());
            query.insert("suffix".to_string(), "T1w".to_string());
            let files = api::ls("MNI152Lin", Some(&query))?;
            Ok(())
        }
    );
    results.insert("list_files_multiple_entities", result);

    // Benchmark: Get metadata
    let result = time_operation(
        "get_metadata",
        "Get template metadata for MNI152Lin",
        20,
        || {
            let metadata = api::get_metadata("MNI152Lin")?;
            Ok(())
        }
    );
    results.insert("get_metadata", result);

    // Benchmark: Get citations
    let result = time_operation(
        "get_citations",
        "Get citations for MNI152Lin",
        20,
        || {
            let citations = api::get_citations("MNI152Lin", false)?;
            Ok(())
        }
    );
    results.insert("get_citations", result);

    // Benchmark: Query all templates for T1w files
    let result = time_operation(
        "query_all_templates_t1w",
        "Query all templates for T1w files",
        5,
        || {
            let templates = api::templates(None)?;
            let mut all_files = Vec::new();
            let mut query = HashMap::new();
            query.insert("suffix".to_string(), "T1w".to_string());

            for template in &templates {
                if let Ok(files) = api::ls(template, Some(&query)) {
                    all_files.extend(files);
                }
            }
            Ok(())
        }
    );
    results.insert("query_all_templates_t1w", result);

    // Output results as JSON
    let json_results = serde_json::to_string_pretty(&results).unwrap();
    println!("\nResults (JSON):");
    println!("{}", json_results);

    // Save to file
    if let Ok(mut path) = std::env::current_dir() {
        path.push("rust_benchmark_results.json");
        std::fs::write(&path, &json_results).unwrap();
        println!("\nResults saved to: {:?}", path);
    }
}

